glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform float uTime;
uniform vec3 bgColor;
uniform vec3 primaryColor;
uniform vec3 secondaryColor;
uniform float panelSoftness;
uniform float grain;
float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7))) * 43758.5453123); }
float noise(vec2 p){
 vec2 i=floor(p), f=fract(p);
 float a=hash(i), b=hash(i+vec2(1.0,0.0)), c=hash(i+vec2(0.0,1.0)), d=hash(i+vec2(1.0,1.0));
 vec2 u=f*f*(3.0-2.0*f);
 return mix(a,b,u.x)+(c-a)*u.y*(1.0-u.x)+(d-b)*u.x*u.y;
}
void main(){
 vec2 uv = vUv;
 vec3 col = bgColor;
 float leftBand = smoothstep(0.333 - panelSoftness, 0.333, uv.x) - smoothstep(0.333, 0.333 + panelSoftness, uv.x);
 float rightBand = smoothstep(0.666 - panelSoftness, 0.666, uv.x) - smoothstep(0.666, 0.666 + panelSoftness, uv.x);
 float arch = smoothstep(0.08, 0.42, 1.0 - abs(uv.y - 0.54));
 float warmField = 0.18 * smoothstep(0.16, 0.84, uv.y);
 col = mix(col, secondaryColor, warmField * 0.35);
 col = mix(col, primaryColor, arch * 0.12 * (1.0 - abs(uv.x - 0.5)));
 col *= 1.0 - 0.12 * (leftBand + rightBand);
 float g = noise(uv * 9.0) * 0.6 + noise(uv * 27.0) * 0.4;
 col *= 0.96 + (g - 0.5) * grain * 0.22;
 float edge = smoothstep(0.0, 0.06, uv.x) * smoothstep(0.0, 0.06, 1.0 - uv.x) * smoothstep(0.0, 0.06, uv.y) * smoothstep(0.0, 0.06, 1.0 - uv.y);
 col = mix(bgColor * 0.88, col, edge);
 gl_FragColor = vec4(col, 1.0);
}

