glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform vec3 primaryColor;
uniform vec3 secondaryColor;
uniform vec3 glowColor;
uniform float width;
uniform float ringCount;
float sdBox(vec2 p, vec2 b){ vec2 d = abs(p)-b; return length(max(d,0.0))+min(max(d.x,d.y),0.0); }
float ring(vec2 p, float r, float t){ float d = abs(length(p)-r); return 1.0-smoothstep(t, t+0.01, d); }
void main(){
 vec2 uv = vUv * 2.0 - 1.0;
 vec3 col = vec3(0.0);
 float shaft = 1.0 - smoothstep(width, width + 0.03, abs(uv.x));
 shaft *= smoothstep(0.98, 0.74, abs(uv.y));
 col += mix(secondaryColor, primaryColor, 0.55 + 0.45 * (1.0 - abs(uv.y))) * shaft;
 for(int i=0;i<7;i++){
 float fi = float(i);
 if(fi >= ringCount) break;
 float y = mix(-0.68, 0.68, fi / max(1.0, ringCount - 1.0));
 vec2 p = uv - vec2(0.0, y);
 float r = mix(0.06, 0.16, 0.5 + 0.5 * sin(fi * 1.7));
 float rg = ring(p, r, 0.012);
 col += mix(glowColor, secondaryColor, fi / max(1.0, ringCount)) * rg * 0.75;
 }
 float cap = 1.0 - smoothstep(0.1, 0.13, sdBox(uv - vec2(0.0, 0.82), vec2(0.18, 0.04)));
 col += glowColor * cap * 0.5;
 gl_FragColor = vec4(col, max(max(col.r, col.g), col.b));
}

