glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform vec3 anchorColor;
uniform vec3 glowColor;
uniform float width;
uniform float tilt;
uniform float offsetX;
void main(){
 vec2 uv = vUv * 2.0 - 1.0;
 float line = abs((uv.x - offsetX) + tilt * uv.y);
 float seam = 1.0 - smoothstep(width, width + 0.012, line);
 float halo = 1.0 - smoothstep(width + 0.02, width + 0.09, line);
 vec3 col = glowColor * halo * 0.22 + anchorColor * seam * 0.46;
 float alpha = max(seam * 0.82, halo * 0.24);
 gl_FragColor = vec4(col, alpha);
}

