glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform float grainScale;
uniform float opacity;
uniform float edgeWear;
float hash(vec2 p){ return fract(sin(dot(p, vec2(41.0,289.0))) * 45758.5453); }
float noise(vec2 p){
 vec2 i=floor(p), f=fract(p);
 float a=hash(i), b=hash(i+vec2(1.0,0.0)), c=hash(i+vec2(0.0,1.0)), d=hash(i+vec2(1.0,1.0));
 vec2 u=f*f*(3.0-2.0*f);
 return mix(a,b,u.x)+(c-a)*u.y*(1.0-u.x)+(d-b)*u.x*u.y;
}
void main(){
 vec2 uv = vUv;
 float g = noise(uv * grainScale) * 0.5 + noise(uv * grainScale * 3.0) * 0.5;
 float edge = 1.0 - smoothstep(0.0, 0.12, min(min(uv.x, 1.0-uv.x), min(uv.y, 1.0-uv.y)));
 vec3 col = vec3((g - 0.5) * 0.32 - edge * edgeWear * 0.22);
 float alpha = opacity * 0.7 + edge * opacity * 0.3;
 gl_FragColor = vec4(col, alpha);
}
